/**
 * getCssValue() function to get css value with unit or without unit
 * it is only for style property - it cannot be used with transform keys
 * @param property - style property
 * @param value - style value
 * @returns - value with unit or without unit
 */
export function getCssValue(property: string, value: number | string) {
  let cssValue;
  if (typeof value === 'number') {
    if (unitlessStyleProps.includes(property)) {
      cssValue = value;
    } else {
      cssValue = value + 'px';
    }
  } else {
    cssValue = value;
  }

  return cssValue;
}
export const styleTrasformKeys = [
  'perspective',
  'translate',
  'translateX',
  'translateY',
  'translateZ',
  'scale',
  'scaleX',
  'scaleY',
  'scaleZ',
  'rotate',
  'rotateX',
  'rotateY',
  'rotateZ',
  'skew',
  'skewX',
  'skewY',
] as const;

function splitCSSValueAndUnit(value: string) {
  const valueMatch = value.match(/(-)?(\d+.)?\d+/g);
  const unitMatch = value.match(
    /px|rem|em|ex|%|cm|mm|in|pt|pc|ch|vh|vw|vmin|vmax/
  );

  return {
    value: Number(valueMatch),
    unit: unitMatch && unitMatch[0],
  };
}

// get unit of transform style property
function getValueUnit(property: string, value: string) {
  let unit;

  const splitValue = splitCSSValueAndUnit(String(value)).value;
  const splitUnit = splitCSSValueAndUnit(String(value)).unit;

  // if string value is passed with unit then split it
  if (splitUnit) {
    return { value: splitValue, unit: splitUnit };
  }

  if (property.includes('translate') || property.includes('perspective')) {
    unit = 'px';
  } else if (property.includes('scale')) {
    unit = '';
  } else if (property.includes('rotate') || property.includes('skew')) {
    unit = 'deg';
  }

  return { value, unit };
}

function getTransformValueWithUnits(property: string, value: string) {
  const valueUnit = getValueUnit(property, value);

  if (
    property.includes('X') ||
    property.includes('Y') ||
    property.includes('Z') ||
    property.includes('perspective') ||
    property.includes('rotate') ||
    property.includes('skew') ||
    property.includes('scale')
  ) {
    // axis value
    return `${property}(${valueUnit.value}${valueUnit.unit})`;
  } else if (property.includes('translate') || property.indexOf('scale')) {
    // two parameter value
    return `${property}(${valueUnit.value}${valueUnit.unit}, ${valueUnit.value}${valueUnit.unit})`;
  } else {
    throw new Error(`Error! Property '${property}' cannot be transformed`);
  }
}

function isTransformKey(key: string) {
  return (styleTrasformKeys as readonly string[]).includes(key);
}

/**
 * getTransform function returns transform string from style object
 */
export function getTransform(style: Record<string, any>) {
  return Object.entries(style)
    .map(([prop, value]) => getTransformValueWithUnits(prop, value))
    .reduce(
      (transform: string, value: string) => (transform += ` ${value}`),
      ''
    )
    .trim();
}

export function separateTransformStyle(style: Record<string, any>) {
  return Object.entries(style).reduce(
    (acc, [property, value]) => {
      if (isTransformKey(property)) {
        acc.transformStyle[property] = value;
      } else {
        acc.nonTransformStyle[property] = value;
      }

      return acc;
    },
    { transformStyle: {}, nonTransformStyle: {} } as {
      transformStyle: Record<string, any>;
      nonTransformStyle: Record<string, any>;
    }
  );
}
import { camelToKebab } from './camelToKebab';
import { getCssValue } from './getCssValue';
import { getTransform, separateTransformStyle } from './transforms';

function applyStyle(ref: { current: any }, style: Record<string, any>) {
  const { nonTransformStyle, transformStyle } = separateTransformStyle(style);

  ref.current.style.transform = getTransform(transformStyle);
  Object.entries(nonTransformStyle).forEach(([property, value]) => {
    ref.current.style[property] = getCssValue(property, value);
  });
}

function applyProps(ref: { current: any }, props: Record<string, any>) {
  Object.entries(props).forEach(([property, value]) => {
    ref.current.setAttribute(camelToKebab(property), value);
  });
}

export function applyFluidValues(
  ref: { current: any },
  props: Record<string, any>
) {
  if (!ref.current) {
    return;
  }

  const { style = {}, ...attrs } = props;
  applyStyle(ref, style);
  applyProps(ref, attrs);
}
/**
 * Converts a camelCase string to kebab-case.
 * e.g. backgroundColor -> background-color
 *
 * @param str - The camelCase string to convert.
 * @returns The converted kebab-case string.
 */
export function camelToKebab(str: string): string {
  return str.replace(/([A-Z])/g, (match) => '-' + match.toLowerCase());
}
