    this.toValue = config.toValue;
    this.mass = config?.mass ?? 1;
    this.tension = config?.tension ?? 170;
    this.friction = config?.friction ?? 26;
    this.delay = config?.delay ?? 0;
  }

  getInternalState(): {
    position: number;
    velocity: number;
    startTime: number;
  } {
    return {
      position: this.position,
      velocity: this.velocity,
      startTime: this.startTime,
    };
  }

  start = (
    value: number,
    onFrame: (value: number) => void,
    onEnd: (result: EndResultType) => void | null,
    previousAnimation: FluidAnimation | null
  ) => {
    const onStart = () => {
      this.isActive = true;
      this.position = value;
      this.onFrame = onFrame;
      this.onEnd = onEnd;
      this.startTime = Date.now();

      if (previousAnimation instanceof Spring) {
        const internalState = previousAnimation.getInternalState();
        this.position = internalState.position || this.position;
        this.velocity = internalState.velocity || this.velocity || 0;
        this.startTime = internalState.startTime || Date.now();
      }

      this.animationFrame = requestAnimationFrame(this.onUpdate.bind(this));
    };

    if (this.delay !== 0) {
      this.timeout = setTimeout(() => onStart(), this.delay);
    } else {
      onStart();
    }
  };

  stop() {
    this.isActive = false;
    clearTimeout(this.timeout);
    cancelAnimationFrame(this.animationFrame);
    this.debouncedOnEnd({ finished: false, value: this.position });
  }

  onUpdate() {
    const now = Date.now();

    const deltaTime = Math.min(now - this.startTime, 64);
    this.startTime = now;

    const c = this.friction;
    const m = this.mass;
    const k = this.tension;

    const v0 = -this.velocity;
    const x0 = this.toValue - this.position;

    const zeta = c / (2 * Math.sqrt(k * m)); // damping ratio
    const omega0 = Math.sqrt(k / m); // undamped angular frequency of the oscillator (rad/ms)
    const omega1 = omega0 * Math.sqrt(1 - zeta ** 2); // exponential decay

    const t = deltaTime / 1000;

    const sin1 = Math.sin(omega1 * t);
