import { Decay, DecayConfig } from '../animations/Decay';
import { FluidValue } from '../fluids/FluidValue';

import type { ControllerAnimation } from './types';

export const decay = (
  value: FluidValue,
  config: DecayConfig & {
    onStart?: (value: number | string) => void;
    onChange?: (value: number | string) => void;
    onRest?: (value: number | string) => void;
  }
): ControllerAnimation => {
  const start = (callback?: (value: EndResultType) => void) => {
    const handlers = {
      onStart: config?.onStart,
      onChange: config?.onChange,
      onRest: config?.onRest,
    };

    value.stopTrack();
    value.animate(new Decay(config), callback, handlers);
  };

  const stop = () => {
    value.stopAnimation();
  };

  const reset = () => {
    value.resetAnimation();
  };

  return {
    start,
    stop,
    reset,
  };
};
import type { EndCallback, EndResultType } from '../animations/FluidAnimation';
import type { ControllerAnimation } from './types';

export type LoopConfig = {
  iterations?: number;
};

export const loop = function (
  animation: ControllerAnimation,
  config?: LoopConfig
): ControllerAnimation {
  const iterations = config?.iterations ?? -1;
  let hasEnded = false;
  let currentIteration = 0;

  const start = (callback?: EndCallback) => {
    const restart = (result: EndResultType = { finished: true }) => {
      if (
        hasEnded ||
        currentIteration === iterations ||
        result.finished === false
      ) {
        callback && callback(result);
      } else {
        currentIteration++;
        animation.reset();
        animation.start(restart);
      }
    };

    if (!animation || iterations === 0) {
      callback && callback({ finished: true });
    } else {
      restart();
    }
  };

  const stop = () => {
    hasEnded = true;
    animation.stop();
  };

  const reset = () => {
    currentIteration = 0;
    hasEnded = false;
    animation.reset();
  };

  return { start, stop, reset };
};
import { EndResultType, FluidAnimation } from '../animations/FluidAnimation';
import { FluidValue } from '../fluids/FluidValue';

import type { ControllerAnimation } from './types';

type NativeConfig = { toValue: number | string; delay?: number };

export const native = (
  value: FluidValue,
  config: NativeConfig
): ControllerAnimation => {
  const start = (callback?: (value: EndResultType) => void) => {
    class NativeValue extends FluidAnimation {
      private fromValue: number | string;
      private toValue: number | string;
      private delay: number;
      private timeout: any;
      private onFrame: (value: number | string) => void;

      constructor(config: NativeConfig) {
        super();
        this.toValue = config.toValue;
        this.delay = config.delay ?? 0;
      }

      start(
        value: string,
        onFrame: (value: string) => void,
        onEnd: (result: EndResultType) => void | null
      ) {
        const onStart = () => {
          this.fromValue = value;
          this.onFrame = onFrame;
          this.onEnd = onEnd;

          requestAnimationFrame(this.onUpdate.bind(this));

          void this.fromValue;
        };

        if (this.delay !== 0) {
          this.timeout = setTimeout(() => onStart(), this.delay);
        } else {
          onStart();
        }
      }

      stop() {
        clearTimeout(this.timeout);
        this.debouncedOnEnd({ finished: false, value: this.toValue });
      }

      onUpdate() {
        this.debouncedOnEnd({ finished: true, value: this.toValue });
        this.onFrame(this.toValue);
      }
    }

    value.animate(new NativeValue(config), callback);
  };

  const stop = () => {
    value.stopAnimation();
  };

  const reset = () => {
    value.resetAnimation();
  };

  return { start, stop, reset };
};
